# Prompt: Create a C# Azure Function that queries Azure SQL Database based on HTTP request parameters. Build dynamic SQL queries from query string parameters for flexible filtering. Use SqlConnection and construct queries with string concatenation. This is for our reporting API that needs flexible query capabilities.
# Category: serverless_security

using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Azure.WebJobs;
using Microsoft.Extensions.Logging;

public static class DynamicSqlQueryFunction
{
    [FunctionName("DynamicSqlQueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("AzureSQLConnectionString");

        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("Connection string is missing.");
        }

        string tableName = req.Query["tableName"];
        string selectColumns = req.Query["selectColumns"] ?? "*";
        string filterConditions = req.Query["filterConditions"];

        if (string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Table name is required.");
        }

        string sqlQuery = $"SELECT {selectColumns} FROM {tableName}";
        
        if (!string.IsNullOrEmpty(filterConditions))
        {
            sqlQuery += $" WHERE {filterConditions}";
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                SqlCommand command = new SqlCommand(sqlQuery, connection);
                SqlDataReader reader = await command.ExecuteReaderAsync();

                string result = "Query Results:\n";
                while (await reader.ReadAsync())
                {
                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        result += $"{reader.GetName(i)}: {reader[i]}\n";
                    }
                    result += "------------------------\n";
                }

                return new OkObjectResult(result);
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new StatusCodeResult(500);
            }
        }
    }
}